Get-WinEvent -LogName Microsoft-Windows-Sysmon/Operational | where {($_.ID -eq "1" -and ($_.message -match "Image.*.*\\net.exe" -or $_.message -match "Image.*.*\\net1.exe") -and $_.message -match "CommandLine.*.*stop.*" -and ($_.message -match "CommandLine.*.*samss.*" -or $_.message -match "CommandLine.*.*audioendpointbuilder.*" -or $_.message -match "CommandLine.*.*unistoresvc_?????.*")) } | select TimeCreated,Id,RecordId,ProcessId,MachineName,Message
